  const payload = buildTaskInsertPayload(insertObject, idempotencyKey);

  const { data: insertedTask, error } = await supabaseAdmin
    .from("tasks")
    .insert(payload)
    .select("id")
    .single();

  if (error) {
    if (
      error.code === "23505" &&
      idempotencyKey &&
      error.message?.includes("idempotency_key")
