/**
 * Extract the command string from an LLM response.
 * Handles structured tool_calls (run(command="...")), plain text with "run(...)",
 * or just bare command text.
 */
/** Strip escaped quotes and trailing junk from extracted command strings. */
function cleanCommand(raw: string): string {
  return raw
    .replace(/\\"/g, '"')   // unescape \"
    .replace(/\\'/g, "'")   // unescape \'
    .replace(/^["']+|["']+$/g, "")  // strip wrapping quotes
    .trim();
}

function extractCommands(responseMessage: Record<string, unknown>): string[] {
  const commands: string[] = [];

  // Structured tool_calls
  const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
    ? (responseMessage as { tool_calls: unknown[] }).tool_calls
    : [];

  for (const tc of rawToolCalls) {
    if (!isRecord(tc)) continue;
    const fn = isRecord(tc.function) ? tc.function : undefined;
    if (!fn || fn.name !== "run") continue;
    const { args } = parseToolArgsSafely(typeof fn.arguments === "string" ? fn.arguments : "{}");
    if (typeof args.command === "string" && args.command.trim()) {
      commands.push(cleanCommand(args.command));
    }
  }
  if (commands.length > 0) return commands;

  // Text fallback
  const text = extractAssistantText(responseMessage);
  if (!text) return [];

  // Multiple run() calls
  const runRe = /run\s*\(\s*(?:command\s*=\s*)?["']([^"']+)["']\s*\)/g;
  let m: RegExpExecArray | null;
  while ((m = runRe.exec(text)) !== null) {
    commands.push(cleanCommand(m[1]));
  }
  if (commands.length > 0) return commands;

  // Numbered list of commands: "1. set-text clip-abc hello\n2. set-text clip-def world"
  // Match lines starting with a number followed by a known command verb
  const COMMAND_VERBS = /^(?:view|move|trim|delete|rm|set|set-text|settext|add-text|addtext|text|duplicate|dup|clone|find-issues|findissues|issues|generate|gen)\b/;
  const lines = text.split('\n');
  for (const line of lines) {
    const stripped = line.replace(/^\s*\d+[.):-]\s*/, '').trim();
    if (stripped && COMMAND_VERBS.test(stripped)) {
      commands.push(cleanCommand(stripped));
    }
  }
  if (commands.length > 0) return commands;

  // Single command formats
  const patterns = [
    /Tool call run:\s*\n?\{?\s*"?command"?\s*[:=]\s*"([^"]+)"/,
    /<parameter\s+name="command">([^<]+)<\/parameter>/,
    /\[TOOL_CALL\][\s\S]*?--command\s+"([^"]+)"[\s\S]*?\[\/TOOL_CALL\]/,
    /command["\s:=]+["']([^"']+)["']/i,
  ];
  for (const re of patterns) {
    const match = text.match(re);
    if (match) return [cleanCommand(match[1])];
  }

  return [];
}

export async function runAgentLoop(
  options: RunAgentLoopOptions,
): Promise<RunAgentLoopResult> {
  const { session, userMessage, selectedClips, supabaseAdmin, logger } = options;

  const lastTurn = session.turns[session.turns.length - 1];
  const isDuplicate = userMessage && lastTurn?.role === "user" && lastTurn.content === userMessage;
  const turns = [...session.turns];
  if (userMessage && !isDuplicate) {
    const userTurn = createTurn("user", userMessage);
    if (selectedClips?.length) {
      userTurn.attachments = selectedClips.map((clip) => ({
        clipId: clip.clip_id,
        url: clip.url,
        mediaType: clip.media_type,
      }));
    }
    turns.push(userTurn);
  }
  let status: AgentSessionStatus = "processing";
  const summary = session.summary;

  try {
    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
    const timelineSummary = viewTimeline(timelineState.config, timelineState.registry).result;
    const systemPrompt = buildTimelineAgentSystemPrompt({
      projectId: timelineState.projectId,
      timelineSummary,
      selectedClips,
    });
    const messages = buildInitialMessages(systemPrompt, turns);
    const startedAt = Date.now();

    // Triage the user message to pick provider: easy/okay → Kimi K2.5, hard → Claude
    const difficulty = userMessage
      ? await triageDifficulty(userMessage, logger)
      : "okay";

    for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
      if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
        status = "continue";
        break;
      }

      const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
      if (currentStatus === "cancelled") {
        status = "cancelled";
        break;
      }

      let completion;
      try {
        completion = await invokeLlm(
          {
            messages: messages as unknown[],
            tools: TIMELINE_AGENT_TOOLS as unknown[],
            tool_choice: "auto",
            temperature: 0.2,
            max_tokens: 4096,
            top_p: 1,
          },
          difficulty,
          logger,
        );
      } catch (llmError: unknown) {
        const text = `AI service error: ${toErrorMessage(llmError)}`;
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      const responseMessage = completion.choices[0]?.message;
      if (!responseMessage) {
        turns.push(createTurn("assistant", "No response from AI."));
        status = "waiting_user";
        break;
      }

      const extractedCommands = extractCommands(responseMessage);
      const assistantText = extractAssistantText(responseMessage);

      // No commands — the model is talking to the user. Pass it through.
      if (extractedCommands.length === 0) {
        const text = assistantText || "What would you like me to do?";
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      // Execute all commands
      let hasError = false;
      for (const command of extractedCommands) {
        console.log(`[agent] Executing command: ${command}`);
        const toolCallId = crypto.randomUUID();
        turns.push(createToolTurn("tool_call", "run", command, { command }));

        messages.push({
          role: "assistant",
          content: null,
          tool_calls: [{
            id: toolCallId,
            type: "function" as const,
            function: { name: "run", arguments: JSON.stringify({ command }) },
          }],
        });

        const result = await executeCommand(
          command,
          timelineState,
          session.timeline_id,
          supabaseAdmin,
        );

        turns.push(createToolTurn("tool_result", "run", result.result, { command }));
        messages.push({
          role: "tool",
          tool_call_id: toolCallId,
          content: result.result,
        });

        const isError = result.result.includes("not found")
          || result.result.includes("does not exist")
          || result.result.includes("requires")
          || result.result.includes("must be")
          || result.result.includes("Failed")
          || result.result.includes("Unknown command")
          || result.result.includes("error");
        if (isError) {
          hasError = true;
          break; // Stop executing remaining commands on error
        }
      }

      // Strip tool-call formatting junk from any assistant text
      if (assistantText) {

      if (assistantText) {
        const cleaned = assistantText
          .replace(/\[TOOL_CALL\][\s\S]*?\[\/TOOL_CALL\]/g, "")
          .replace(/<invoke[\s\S]*?<\/invoke>/g, "")
          .replace(/Tool call \w+:[\s\S]*?(?=\n\n|$)/g, "")
          .replace(/run\s*\([^)]*\)/g, "")
          .replace(/^\s*\d+[.):-]\s*(set-text|move|trim|delete|duplicate|add-text|set|view|find-issues|generate)\b.*$/gm, "")
          .trim();
        if (cleaned && cleaned.length > 2) {
          turns.push(createTurn("assistant", cleaned));
        }
      }

      // If a command failed, give the model structured recovery options
      if (hasError) {
        const lastResult = turns[turns.length - 1];
        messages.push({
          role: "user",
          content: `Command failed: "${lastResult?.content ?? "unknown error"}". You can: (1) run(command="...") with a corrected command, (2) run(command="view") to inspect the timeline, or (3) reply in plain text to tell the user what went wrong.`,
        });
        continue;
      }
    }

    if (status === "processing") {
      status = "continue";
    }

    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    logger.info("Agent loop completed", {
      session_id: session.id,
      status,
      turns_added: turns.length - session.turns.length,
    });

    return { status, turns, summary };
  } catch (error: unknown) {
    const errorDetail = toErrorMessage(error);
    console.error(`[agent] FATAL: ${errorDetail}`);
    logger.error("Agent loop failed", {
      session_id: session.id,
      error: errorDetail,
    });

    turns.push(createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`));

    try {
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status: "error",
        turns,
        summary,
      });
    } catch (persistError: unknown) {
      logger.error("Failed to persist error state", {
        session_id: session.id,
        error: toErrorMessage(persistError),
      });
    }

    return { status: "error", turns, summary };
  }
}

import type { TimelineConfig } from "../../../src/tools/video-editor/types/index.ts";
import { isRecord, isSessionStatus, normalizeTimelineRow } from "./llm/messages.ts";
import type {
  AgentSessionStatus,
  AgentTurn,
  SupabaseAdmin,
  TimelineState,
} from "./types.ts";

export async function loadTimelineState(
  supabaseAdmin: SupabaseAdmin,
  timelineId: string,
): Promise<TimelineState> {
  const { data, error } = await supabaseAdmin
    .from("timelines")
    .select("config, config_version, asset_registry, project_id")
    .eq("id", timelineId)
    .maybeSingle();

  if (error) {
    throw new Error(`Failed to load timeline: ${error.message}`);
  }

  if (!data || !isRecord(data)) {
    throw new Error("Timeline not found");
  }

  const normalized = normalizeTimelineRow(data);
  return {
    config: normalized.config,
    configVersion: normalized.config_version,
    registry: normalized.asset_registry,
    projectId: normalized.project_id,
  };
}

export async function saveTimelineConfigVersioned(
  supabaseAdmin: SupabaseAdmin,
  timelineId: string,
  expectedVersion: number,
  config: TimelineConfig,
  retries = 2,
): Promise<number | null> {
  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const { data, error } = await supabaseAdmin
        .rpc("update_timeline_config_versioned", {
          p_timeline_id: timelineId,
          p_expected_version: expectedVersion,
          p_config: config,
        })
        .maybeSingle();

      if (error) {
        // Connection errors are retryable
        if (attempt < retries && (error.message.includes("connection") || error.message.includes("reset") || error.message.includes("SendRequest"))) {
          console.warn(`[agent] DB save failed (attempt ${attempt + 1}), retrying: ${error.message}`);
          await new Promise((r) => setTimeout(r, 500 * (attempt + 1)));
          continue;
        }
        throw new Error(`Failed to save timeline config: ${error.message}`);
      }

      const nextVersion = (data as { config_version?: unknown } | null)?.config_version;
      return typeof nextVersion === "number" ? nextVersion : null;
    } catch (err: unknown) {
      if (attempt < retries && err instanceof Error && (err.message.includes("connection") || err.message.includes("reset") || err.message.includes("SendRequest"))) {
        console.warn(`[agent] DB save threw (attempt ${attempt + 1}), retrying: ${err.message}`);
        await new Promise((r) => setTimeout(r, 500 * (attempt + 1)));
        continue;
      }
      throw err;
    }
  }
  throw new Error("Failed to save timeline config after retries");
}

export async function loadSessionStatus(
  supabaseAdmin: SupabaseAdmin,
  sessionId: string,
): Promise<AgentSessionStatus | null> {
  const { data, error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .select("status")
    .eq("id", sessionId)
    .maybeSingle();

  if (error || !data || !isRecord(data)) {
    return null;
  }

  return isSessionStatus(data.status) ? data.status : null;
}

export async function persistSessionState(
  supabaseAdmin: SupabaseAdmin,
  options: {
    sessionId: string;
    status: AgentSessionStatus;
    turns: AgentTurn[];
    summary: string | null;
  },
): Promise<void> {
  const { error } = await supabaseAdmin
    .from("timeline_agent_sessions")
    .update({
      status: options.status,
      turns: options.turns,
      summary: options.summary,
      updated_at: new Date().toISOString(),
    })
    .eq("id", options.sessionId);

  if (error) {
    throw new Error(`Failed to persist session state: ${error.message}`);
  }
}

import { parseCommand, validateCommand, type ParsedCommand } from "../command-parser.ts";
import { loadTimelineState, saveTimelineConfigVersioned } from "../db.ts";
import type {
  SupabaseAdmin,
  TimelineState,
  ToolContext,
  ToolResult,
} from "../types.ts";
import { handlers as timelineHandlers } from "./timeline.ts";
import { createGenerationTask } from "./generation.ts";

// Map parsed command types to timeline tool names
const COMMAND_TO_TOOL: Record<string, string> = {
  view: "view_timeline",
  move: "move_clip",
  trim: "trim_clip",
  delete: "delete_clip",
  set: "set_clip_property",
  "set-text": "set_text_content",
  duplicate: "duplicate_clip",
  "add-text": "add_text_clip",
  "find-issues": "find_issues",
  // "repeat" is handled specially in executeCommand, not mapped to a tool
};

function commandToToolArgs(parsed: ParsedCommand): Record<string, unknown> {
  switch (parsed.type) {
    case "view": return {};
    case "move": return { clipId: parsed.clipId, at: parsed.at };
    case "trim": return { clipId: parsed.clipId, from: parsed.from, to: parsed.to, duration: parsed.duration };
    case "delete": return { clipId: parsed.clipId };
    case "set-text": return { clipId: parsed.clipId, text: parsed.text };
    case "duplicate": return { clipId: parsed.clipId, count: parsed.count };
    case "set": return { clipId: parsed.clipId, property: parsed.property, value: parsed.value };
    case "add-text": return { track: parsed.track, at: parsed.at, duration: parsed.duration, text: parsed.text };
    case "find-issues": return {};
    case "generate": return { prompt: parsed.prompt, count: parsed.count };
    default: return {};
  }
}

function buildContext(state: TimelineState): ToolContext {
  return {
    config: state.config,
    registry: state.registry,
    projectId: state.projectId,
  };
}

export async function executeCommand(
  command: string,
  state: TimelineState,
  timelineId: string,
  supabaseAdmin: SupabaseAdmin,
): Promise<ToolResult> {
  const parsed = parseCommand(command);

  if (parsed.type === "error") {
    return { result: parsed.message };
  }

  // Validate against current timeline state
  const validationError = validateCommand(parsed, state.config, state.registry);
  if (validationError) {
    return { result: validationError };
  }

  // Handle repeat: expand template, execute all in memory, save once at end
  if (parsed.type === "repeat") {
    const errorMessages: string[] = [];
    let errors = 0;
    let succeeded = 0;

    for (let i = 0; i < parsed.count; i++) {
      const value = parsed.from + parsed.step * i;
      const roundedValue = Math.round(value * 1000) / 1000;
      const expanded = parsed.template.replace(
        new RegExp(`\\{${parsed.varName}\\}`, "g"),
        String(roundedValue),
      );

      // Parse and validate the sub-command but execute in memory only (no DB save)
      const subParsed = parseCommand(expanded);
      if (subParsed.type === "error") {
        errorMessages.push(`${i + 1}. ${subParsed.message}`);
        errors++;
        if (errors >= 3) { errorMessages.push("Stopped after 3 errors."); break; }
        continue;
      }

      const subValidation = validateCommand(subParsed, state.config, state.registry);
      if (subValidation) {
        errorMessages.push(`${i + 1}. ${subValidation}`);
        errors++;
        if (errors >= 3) { errorMessages.push("Stopped after 3 errors."); break; }
        continue;
      }

      const toolName = COMMAND_TO_TOOL[subParsed.type];
      const handler = toolName ? timelineHandlers[toolName] : undefined;
      if (!handler) {
        errorMessages.push(`${i + 1}. No handler for "${subParsed.type}".`);
        errors++;
        continue;
      }

      const args = commandToToolArgs(subParsed);
      const ctx = buildContext(state);
      const result = await handler(args, ctx);

      if (result.config) {
        // Apply to in-memory state without saving to DB
        state.config = result.config;
      }
      succeeded++;
    }

    // Save once at the end
    if (succeeded > 0) {
      const nextVersion = await saveTimelineConfigVersioned(
        supabaseAdmin, timelineId, state.configVersion, state.config,
      );
      if (nextVersion !== null) {
        state.configVersion = nextVersion;
      } else {
        return { result: `Executed ${succeeded} commands in memory but failed to save — version conflict.` };
      }
    }

    return {
      config: succeeded > 0 ? state.config : undefined,
      result: `Repeated ${succeeded}/${parsed.count}.${errorMessages.length > 0 ? "\n" + errorMessages.join("\n") : ""}`,
    };
  }

  // Handle generation separately (async, not a timeline tool)
  if (parsed.type === "generate") {
    return await createGenerationTask({
      project_id: state.projectId,
      prompt: parsed.prompt,
      count: parsed.count,
    });
  }

  // Route to timeline tool
  const toolName = COMMAND_TO_TOOL[parsed.type];
  const handler = toolName ? timelineHandlers[toolName] : undefined;
  if (!handler) {
    return { result: `Internal error: no handler for command type "${parsed.type}".` };
  }

  const args = commandToToolArgs(parsed);
  const ctx = buildContext(state);

  const runTool = () => handler(args, ctx);
  let result = await runTool();

  if (!result.config) {
    return result;
  }

  // Versioned save with retry
  let nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion !== null) {
    state.config = result.config;
    state.configVersion = nextVersion;
    return result;
  }

  // Reload and retry once on version conflict
  const refreshedState = await loadTimelineState(supabaseAdmin, timelineId);
  state.config = refreshedState.config;
  state.configVersion = refreshedState.configVersion;
  state.registry = refreshedState.registry;
  state.projectId = refreshedState.projectId;

  const retryCtx = buildContext(state);
  result = await handler(args, retryCtx);
  if (!result.config) {
    return { result: `${result.result} (retried after reload.)` };
  }

  nextVersion = await saveTimelineConfigVersioned(
    supabaseAdmin,
    timelineId,
    state.configVersion,
    result.config,
  );

  if (nextVersion === null) {
    return { result: "Version conflict. Please retry." };
  }

  state.config = result.config;
  state.configVersion = nextVersion;
  return { ...result, result: `${result.result} (retried after reload.)` };
}

import type { ResolverResult, TaskFamilyResolver, TaskInsertObject } from "./types.ts";
import { generateTaskId } from "./shared/ids.ts";
import { mapPathLorasToStrengthRecord, validateLoraConfigs } from "./shared/loras.ts";
import { resolveImageGenerationResolution } from "./shared/resolution.ts";
import { validateSeed32Bit } from "./shared/seed.ts";
import {
  TaskValidationError,
  validateNonEmptyString,
  validateRequiredFields,
} from "./shared/validation.ts";

interface PathLoraConfig {
  path: string;
  strength: number;
}

type ReferenceMode = "style" | "subject" | "style-character" | "scene" | "custom";

interface BatchImageGenerationTaskInput {
  prompts: Array<{ id: string; fullPrompt: string; shortPrompt?: string }>;
  imagesPerPrompt: number;
  loras?: PathLoraConfig[];
  shot_id?: string;
  resolution?: string;
  resolution_scale?: number;
  resolution_mode?: "project" | "custom";
  custom_aspect_ratio?: string;
  model_name?: string;
  steps?: number;
  negative_prompt?: string;
  seed?: number;
  style_reference_image?: string;
  subject_reference_image?: string;
  style_reference_strength?: number;
  subject_strength?: number;
  subject_description?: string;
  in_this_scene?: boolean;
  in_this_scene_strength?: number;
  reference_mode?: ReferenceMode;
  hires_scale?: number;
  hires_steps?: number;
  hires_denoise?: number;
  lightning_lora_strength_phase_1?: number;
  lightning_lora_strength_phase_2?: number;
  additional_loras?: Record<string, number>;
}

const IN_SCENE_LORA_URL = "https://huggingface.co/peteromallet/random_junk/resolve/main/in_scene_different_object_000010500.safetensors";

function buildQueuedTask(
  projectId: string,
  taskType: string,
  params: Record<string, unknown>,
): TaskInsertObject {
  return {
    project_id: projectId,
    task_type: taskType,
    params,
    status: "Queued",
    created_at: new Date().toISOString(),
    dependant_on: null,
  };
}

function validateImageGenerationInput(input: BatchImageGenerationTaskInput): void {
  validateRequiredFields(input, ["prompts", "imagesPerPrompt"]);

  if (input.prompts.length === 0) {
    throw new TaskValidationError("At least one prompt is required", "prompts");
  }
  if (input.imagesPerPrompt < 1 || input.imagesPerPrompt > 16) {
    throw new TaskValidationError("Images per prompt must be between 1 and 16", "imagesPerPrompt");
  }

  input.prompts.forEach((prompt, index) => {
    validateNonEmptyString(prompt.fullPrompt, `prompts[${index}].fullPrompt`, `Prompt ${index + 1}`);
  });

  validateSeed32Bit(input.seed);
  validateLoraConfigs(input.loras, {
    pathField: "path",
    strengthField: "strength",
    strengthLabel: "strength",
    min: 0,
    max: 2,
  });
}

function buildTaskType(input: BatchImageGenerationTaskInput): string {
  switch (input.model_name) {
    case "qwen-image":
      return input.style_reference_image ? "qwen_image_style" : "qwen_image";
    case "qwen-image-2512":
      return "qwen_image_2512";
    case "z-image":
      return "z_image_turbo";
    default:
      return "wan_2_2_t2i";
  }
}

function supportsReferenceParams(input: BatchImageGenerationTaskInput): boolean {
  return input.model_name?.startsWith("qwen-image") === true || input.model_name === "z-image";
}

function filterReferenceSettingsByMode(
  referenceMode: ReferenceMode | undefined,
  settings: Record<string, unknown>,
): Record<string, unknown> {
  if (!referenceMode || referenceMode === "custom") {
    return settings;
  }

  const filtered: Record<string, unknown> = {};
  switch (referenceMode) {
    case "style":
      if (settings.style_reference_strength !== undefined) filtered.style_reference_strength = settings.style_reference_strength;
      break;
    case "subject":
      filtered.style_reference_strength = 1.1;
      filtered.subject_strength = 0.5;
      if (typeof settings.subject_description === "string" && settings.subject_description.trim()) {
        filtered.subject_description = settings.subject_description;
      }
      break;
    case "style-character":
      if (settings.style_reference_strength !== undefined) filtered.style_reference_strength = settings.style_reference_strength;
      if (settings.subject_strength !== undefined) filtered.subject_strength = settings.subject_strength;
      if (typeof settings.subject_description === "string" && settings.subject_description.trim()) {
        filtered.subject_description = settings.subject_description;
      }
      break;
    case "scene":
      filtered.style_reference_strength = 1.1;
      filtered.in_this_scene = true;
      filtered.in_this_scene_strength = 0.5;
      break;
  }
  return filtered;
}

function buildLorasParam(
  loras: PathLoraConfig[] | undefined,
  inSceneLora?: { url: string; strength: number },
): { additional_loras?: Record<string, number> } {
  const lorasMap = mapPathLorasToStrengthRecord(loras);
  if (inSceneLora && inSceneLora.strength > 0) {
    lorasMap[inSceneLora.url] = inSceneLora.strength;
  }
  return Object.keys(lorasMap).length > 0 ? { additional_loras: lorasMap } : {};
}

function buildReferenceParams(input: BatchImageGenerationTaskInput): Record<string, unknown> {
  if (!input.style_reference_image) {
    return {};
  }

  const filteredSettings = filterReferenceSettingsByMode(input.reference_mode, {
    style_reference_strength: input.style_reference_strength,
    subject_strength: input.subject_strength,
    subject_description: input.subject_description,
    in_this_scene: input.in_this_scene,
    in_this_scene_strength: input.in_this_scene_strength,
  });

  return {
    style_reference_image: input.style_reference_image,
    subject_reference_image: input.subject_reference_image || input.style_reference_image,
    ...filteredSettings,
    ...(filteredSettings.in_this_scene_strength !== undefined
      ? { scene_reference_strength: filteredSettings.in_this_scene_strength }
      : {}),
  };
}

function buildHiresOverride(
  input: BatchImageGenerationTaskInput,
  baseLoras: Record<string, number> = {},
): Record<string, unknown> {
  return {
    ...(input.hires_scale !== undefined ? { hires_scale: input.hires_scale } : {}),
    ...(input.hires_steps !== undefined ? { hires_steps: input.hires_steps } : {}),
    ...(input.hires_denoise !== undefined ? { hires_denoise: input.hires_denoise } : {}),
    ...(input.additional_loras && Object.keys(input.additional_loras).length > 0
      ? { additional_loras: { ...baseLoras, ...input.additional_loras } }
      : {}),
  };
}

function buildTaskParams(
  input: BatchImageGenerationTaskInput,
  prompt: string,
  taskType: string,
  finalResolution: string,
  seed: number,
): Record<string, unknown> {
  const taskId = generateTaskId(taskType);
  const lorasParam = buildLorasParam(
    input.loras,
    supportsReferenceParams(input) && input.in_this_scene && input.in_this_scene_strength
      ? { url: IN_SCENE_LORA_URL, strength: input.in_this_scene_strength }
      : undefined,
  );

  const referenceParams = supportsReferenceParams(input) ? buildReferenceParams(input) : {};
  const hiresOverride = buildHiresOverride(input, lorasParam.additional_loras);

  return {
    task_id: taskId,
    model: input.model_name ?? "optimised-t2i",
    prompt,
    resolution: finalResolution,
    seed,
    steps: input.steps ?? 12,
    add_in_position: false,
    ...(input.negative_prompt ? { negative_prompt: input.negative_prompt } : {}),
    ...lorasParam,
    ...referenceParams,
    ...hiresOverride,
    ...(input.shot_id ? { shot_id: input.shot_id } : {}),
    ...(input.lightning_lora_strength_phase_1 !== undefined
      ? { lightning_lora_strength_phase_1: input.lightning_lora_strength_phase_1 }
      : {}),
    ...(input.lightning_lora_strength_phase_2 !== undefined
      ? { lightning_lora_strength_phase_2: input.lightning_lora_strength_phase_2 }
      : {}),
  };
}

export const imageGenerationResolver: TaskFamilyResolver = (request, context): ResolverResult => {
  const input = request.input as unknown as BatchImageGenerationTaskInput;
  validateImageGenerationInput(input);

  const finalResolution = resolveImageGenerationResolution({
    aspectRatio: context.aspectRatio,
    customResolution: input.resolution,
    modelName: input.model_name,
    resolutionScale: input.resolution_scale,
    resolutionMode: input.resolution_mode,
    customAspectRatio: input.custom_aspect_ratio,

    customAspectRatio: input.custom_aspect_ratio,
  }).resolution;
  const taskType = buildTaskType(input);
  const totalTaskCount = input.prompts.length * input.imagesPerPrompt;
  const baseSeed = input.seed ?? Math.floor(Math.random() * 0x7fffffff);
  let taskIndex = 0;

  const tasks = input.prompts.flatMap((promptEntry) => {
    return Array.from({ length: input.imagesPerPrompt }, () => {
      const seed = totalTaskCount > 1 ? baseSeed + taskIndex++ : baseSeed;
      const params = buildTaskParams(
        input,
        promptEntry.fullPrompt,
        taskType,
        finalResolution,
        seed,
      );
      return buildQueuedTask(context.projectId, taskType, params);
    });
  });

  return { tasks };
};

