  AgentSession,
  AgentSessionStatus,
  AgentTurn,
  SelectedClipPayload,
  SupabaseAdmin,
} from "./types.ts";

type LoopLogger = Pick<EdgeRuntime["logger"], "error" | "info">;

export interface RunAgentLoopOptions {
  session: AgentSession;
  userMessage?: string;
  selectedClips?: SelectedClipPayload[];
  supabaseAdmin: SupabaseAdmin;
  logger: LoopLogger;
}

export interface RunAgentLoopResult {
  status: AgentSessionStatus;
  turns: AgentTurn[];
  summary: string | null;
}

/**
 * Extract the command string from an LLM response.
 * Handles structured tool_calls (run(command="...")), plain text with "run(...)",
 * or just bare command text.
 */
/** Strip escaped quotes and trailing junk from extracted command strings. */
function cleanCommand(raw: string): string {
  return raw
    .replace(/\\"/g, '"')   // unescape \"
    .replace(/\\'/g, "'")   // unescape \'
    .replace(/^["']+|["']+$/g, "")  // strip wrapping quotes
    .trim();
}

function extractCommands(responseMessage: Record<string, unknown>): string[] {
  const commands: string[] = [];

  // Structured tool_calls
  const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
    ? (responseMessage as { tool_calls: unknown[] }).tool_calls
    : [];

  for (const tc of rawToolCalls) {
    if (!isRecord(tc)) continue;
    const fn = isRecord(tc.function) ? tc.function : undefined;
    if (!fn || fn.name !== "run") continue;
    const { args } = parseToolArgsSafely(typeof fn.arguments === "string" ? fn.arguments : "{}");
    if (typeof args.command === "string" && args.command.trim()) {
      commands.push(cleanCommand(args.command));
    }
  }
  if (commands.length > 0) return commands;

  // Text fallback
  const text = extractAssistantText(responseMessage);
  if (!text) return [];

  // Multiple run() calls
  const runRe = /run\s*\(\s*(?:command\s*=\s*)?["']([^"']+)["']\s*\)/g;
  let m: RegExpExecArray | null;
  while ((m = runRe.exec(text)) !== null) {
    commands.push(cleanCommand(m[1]));
  }
  if (commands.length > 0) return commands;

  // Numbered list of commands: "1. set-text clip-abc hello\n2. set-text clip-def world"
  // Match lines starting with a number followed by a known command verb
  const COMMAND_VERBS = /^(?:view|move|trim|delete|rm|set|set-text|settext|add-text|addtext|text|duplicate|dup|clone|find-issues|findissues|issues|generate|gen)\b/;
  const lines = text.split('\n');
  for (const line of lines) {
    const stripped = line.replace(/^\s*\d+[.):-]\s*/, '').trim();
    if (stripped && COMMAND_VERBS.test(stripped)) {
      commands.push(cleanCommand(stripped));
    }
  }
  if (commands.length > 0) return commands;

  // Single command formats
  const patterns = [
    /Tool call run:\s*\n?\{?\s*"?command"?\s*[:=]\s*"([^"]+)"/,
    /<parameter\s+name="command">([^<]+)<\/parameter>/,
    /\[TOOL_CALL\][\s\S]*?--command\s+"([^"]+)"[\s\S]*?\[\/TOOL_CALL\]/,
    /command["\s:=]+["']([^"']+)["']/i,
  ];
  for (const re of patterns) {
    const match = text.match(re);
    if (match) return [cleanCommand(match[1])];
  }

  return [];
}

export async function runAgentLoop(
  options: RunAgentLoopOptions,
): Promise<RunAgentLoopResult> {
  const { session, userMessage, selectedClips, supabaseAdmin, logger } = options;

  const lastTurn = session.turns[session.turns.length - 1];
  const isDuplicate = userMessage && lastTurn?.role === "user" && lastTurn.content === userMessage;
  const turns = [...session.turns];
  if (userMessage && !isDuplicate) {
    const userTurn = createTurn("user", userMessage);
    if (selectedClips?.length) {
      userTurn.attachments = selectedClips.map((clip) => ({
        clipId: clip.clip_id,
        url: clip.url,
        mediaType: clip.media_type,
      }));
    }
    turns.push(userTurn);
  }
  let status: AgentSessionStatus = "processing";
  const summary = session.summary;

  try {
    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
    const timelineSummary = viewTimeline(timelineState.config, timelineState.registry).result;
    const systemPrompt = buildTimelineAgentSystemPrompt({
      projectId: timelineState.projectId,
      timelineSummary,
      selectedClips,
    });
    const messages = buildInitialMessages(systemPrompt, turns);
    const startedAt = Date.now();

    // Triage the user message to pick provider: easy/okay → Kimi K2.5, hard → Claude
    const difficulty = userMessage
      ? await triageDifficulty(userMessage, logger)
      : "okay";

    for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
      if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
        status = "continue";
        break;
      }

      const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
      if (currentStatus === "cancelled") {
        status = "cancelled";
        break;
      }

      let completion;
      try {
        completion = await invokeLlm(
          {
            messages: messages as unknown[],
            tools: TIMELINE_AGENT_TOOLS as unknown[],
            tool_choice: "auto",
            temperature: 0.2,
            max_tokens: 4096,
            top_p: 1,
          },
          difficulty,
          logger,
        );
      } catch (llmError: unknown) {
        const text = `AI service error: ${toErrorMessage(llmError)}`;
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      const responseMessage = completion.choices[0]?.message;
      if (!responseMessage) {
        turns.push(createTurn("assistant", "No response from AI."));
        status = "waiting_user";
        break;
      }

      const extractedCommands = extractCommands(responseMessage);
      const assistantText = extractAssistantText(responseMessage);

      // No commands — the model is talking to the user. Pass it through.
      if (extractedCommands.length === 0) {
        const text = assistantText || "What would you like me to do?";
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      // Execute all commands
      let hasError = false;
      for (const command of extractedCommands) {
        console.log(`[agent] Executing command: ${command}`);
        const toolCallId = crypto.randomUUID();
        turns.push(createToolTurn("tool_call", "run", command, { command }));

        messages.push({
          role: "assistant",
          content: null,
          tool_calls: [{
            id: toolCallId,
            type: "function" as const,
            function: { name: "run", arguments: JSON.stringify({ command }) },
          }],
        });

        const result = await executeCommand(
          command,
          timelineState,
          session.timeline_id,
          supabaseAdmin,
        );

        turns.push(createToolTurn("tool_result", "run", result.result, { command }));
        messages.push({
          role: "tool",
          tool_call_id: toolCallId,
          content: result.result,
        });

        const isError = result.result.includes("not found")
          || result.result.includes("does not exist")
          || result.result.includes("requires")
          || result.result.includes("must be")
          || result.result.includes("Failed")
          || result.result.includes("Unknown command")
          || result.result.includes("error");
        if (isError) {
          hasError = true;
          break; // Stop executing remaining commands on error
        }
      }

      // Strip tool-call formatting junk from any assistant text
      if (assistantText) {
        const cleaned = assistantText
          .replace(/\[TOOL_CALL\][\s\S]*?\[\/TOOL_CALL\]/g, "")
          .replace(/<invoke[\s\S]*?<\/invoke>/g, "")
          .replace(/Tool call \w+:[\s\S]*?(?=\n\n|$)/g, "")
          .replace(/run\s*\([^)]*\)/g, "")
          .replace(/^\s*\d+[.):-]\s*(set-text|move|trim|delete|duplicate|add-text|set|view|find-issues|generate)\b.*$/gm, "")
          .trim();
        if (cleaned && cleaned.length > 2) {
          turns.push(createTurn("assistant", cleaned));
        }
      }

      // If a command failed, give the model structured recovery options
      if (hasError) {
        const lastResult = turns[turns.length - 1];
        messages.push({
          role: "user",
          content: `Command failed: "${lastResult?.content ?? "unknown error"}". You can: (1) run(command="...") with a corrected command, (2) run(command="view") to inspect the timeline, or (3) reply in plain text to tell the user what went wrong.`,
        });
        continue;
      }
    }

    if (status === "processing") {
      status = "continue";
    }

    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    logger.info("Agent loop completed", {
      session_id: session.id,
      status,
      turns_added: turns.length - session.turns.length,
    });

    return { status, turns, summary };
  } catch (error: unknown) {
    const errorDetail = toErrorMessage(error);
    console.error(`[agent] FATAL: ${errorDetail}`);
    logger.error("Agent loop failed", {
      session_id: session.id,
      error: errorDetail,
    });

    turns.push(createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`));

    try {
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status: "error",
        turns,
        summary,
      });
    } catch (persistError: unknown) {
      logger.error("Failed to persist error state", {
        session_id: session.id,
        error: toErrorMessage(persistError),
      });
    }

    return { status: "error", turns, summary };
  }
}

import { toErrorMessage } from "../../_shared/errorMessage.ts";
import { MAX_CONTEXT_TURNS } from "../config.ts";
import type {
  AgentSession,
  AgentSessionStatus,
  AgentTurn,
  LlmMessage,
  TimelineRow,
} from "../types.ts";
import type { AssetRegistry, TimelineConfig } from "../../../../src/tools/video-editor/types/index.ts";

export function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export function isSessionStatus(value: unknown): value is AgentSessionStatus {
  return value === "waiting_user"
    || value === "processing"
    || value === "continue"
    || value === "done"
    || value === "cancelled"
    || value === "error";
}

export function normalizeTurns(value: unknown): AgentTurn[] {
  if (!Array.isArray(value)) {
    return [];
  }

  return value.flatMap((item) => {
    if (!isRecord(item) || typeof item.content !== "string" || typeof item.timestamp !== "string") {
      return [];
    }

    const role = item.role;
    if (role !== "user" && role !== "assistant" && role !== "tool_call" && role !== "tool_result") {
      return [];
    }

    return [{
      role,
      content: item.content,
      attachments: Array.isArray(item.attachments) ? item.attachments : undefined,
      tool_name: typeof item.tool_name === "string" ? item.tool_name : undefined,
      tool_args: isRecord(item.tool_args) ? item.tool_args : undefined,
      timestamp: item.timestamp,
    }];
  });
}

export function createTurn(role: AgentTurn["role"], content: string): AgentTurn {
  return {
    role,
    content,
    timestamp: new Date().toISOString(),
  };
}

export function createToolTurn(
  role: Extract<AgentTurn["role"], "tool_call" | "tool_result">,
  toolName: string,
  content: string,
  toolArgs: Record<string, unknown>,
): AgentTurn {
  return {
    role,
    content,
    tool_name: toolName,
    tool_args: toolArgs,
    timestamp: new Date().toISOString(),
  };
}

export function normalizeSessionRow(row: Record<string, unknown>): AgentSession {
  return {
    id: typeof row.id === "string" ? row.id : "",
    timeline_id: typeof row.timeline_id === "string" ? row.timeline_id : "",
    user_id: typeof row.user_id === "string" ? row.user_id : "",
    status: isSessionStatus(row.status) ? row.status : "error",
    turns: normalizeTurns(row.turns),
    model: typeof row.model === "string" ? row.model : "openrouter",
    summary: typeof row.summary === "string" ? row.summary : null,
    created_at: typeof row.created_at === "string" ? row.created_at : "",
    updated_at: typeof row.updated_at === "string" ? row.updated_at : "",
  };
}

export function normalizeTimelineRow(row: Record<string, unknown>): TimelineRow {
  return {
    config: (row.config as TimelineConfig | null)
      ?? { output: { resolution: "1920x1080", fps: 30, file: "output.mp4" }, clips: [] },
    config_version: typeof row.config_version === "number" ? row.config_version : 1,
    asset_registry: (row.asset_registry as AssetRegistry | null) ?? { assets: {} },
    project_id: typeof row.project_id === "string" ? row.project_id : "",
  };
}

export function parseToolArgsSafely(rawArguments: unknown): {
  args: Record<string, unknown>;
  error: string | null;
} {
  if (typeof rawArguments !== "string" || !rawArguments.trim()) {
    return { args: {}, error: null };
  }

  try {
    const parsed = JSON.parse(rawArguments);
    // Accept null, empty arrays, etc. as "no args" — only reject non-object primitives like strings/numbers
    if (parsed === null || parsed === undefined) {
      return { args: {}, error: null };
    }
    if (typeof parsed !== "object") {
      console.warn(`[agent] Tool args parsed to non-object: ${typeof parsed} — ${rawArguments.slice(0, 100)}`);
      return { args: {}, error: null };
    }
    return { args: isRecord(parsed) ? parsed : {}, error: null };
  } catch (error: unknown) {
    console.warn(`[agent] Failed to parse tool args: ${rawArguments.slice(0, 200)}`);
    return {
      args: {},
      error: `Invalid tool arguments JSON: ${toErrorMessage(error)}`,
    };
  }
}

export function formatToolArgs(toolArgs: Record<string, unknown>): string {
  return JSON.stringify(toolArgs, null, 2);
}

export function summarizeStoredToolTurn(turn: AgentTurn): string {
  const toolName = turn.tool_name ?? "tool";
  if (turn.role === "tool_call") {
    return `Tool call ${toolName}:\n${formatToolArgs(turn.tool_args ?? {})}`;
  }

  return `Tool result ${toolName}: ${turn.content}`;
}

export function buildInitialMessages(
  systemPrompt: string,
  turns: AgentTurn[],
): LlmMessage[] {
  const messages: LlmMessage[] = [{ role: "system", content: systemPrompt }];

  // Only send the most recent turns to avoid blowing up the context window.
  const recentTurns = turns.length > MAX_CONTEXT_TURNS
    ? turns.slice(-MAX_CONTEXT_TURNS)
    : turns;

  for (const turn of recentTurns) {
    if (turn.role === "user") {
      messages.push({ role: "user", content: turn.content });
      continue;
    }

    if (turn.role === "assistant") {
      messages.push({ role: "assistant", content: turn.content });
      continue;
    }

    messages.push({
      role: "assistant",
      content: summarizeStoredToolTurn(turn),
    });
  }

  return messages;
}

export function extractAssistantText(message: { content?: unknown }): string {
  if (typeof message.content === "string") {
    return message.content.trim();
  }

  if (!Array.isArray(message.content)) {
    return "";
  }

  return message.content
    .flatMap((item) => {
      if (!isRecord(item)) {
        return [];
      }

      const text = item.text;
      return typeof text === "string" ? [text] : [];
    })
    .join("\n")
    .trim();
}

