/**
 * Extract the command string from an LLM response.
 * Handles structured tool_calls (run(command="...")), plain text with "run(...)",
 * or just bare command text.
 */
/** Strip escaped quotes and trailing junk from extracted command strings. */
function cleanCommand(raw: string): string {
  return raw
    .replace(/\\"/g, '"')   // unescape \"
    .replace(/\\'/g, "'")   // unescape \'
    .replace(/^["']+|["']+$/g, "")  // strip wrapping quotes
    .trim();
}

function extractToolCalls(responseMessage: Record<string, unknown>): ExtractedToolCall[] {
  const rawToolCalls = Array.isArray((responseMessage as { tool_calls?: unknown[] }).tool_calls)
    ? (responseMessage as { tool_calls: unknown[] }).tool_calls
    : [];

  for (const tc of rawToolCalls) {
    if (!isRecord(tc)) continue;
    const fn = isRecord(tc.function) ? tc.function : undefined;
    if (!fn || typeof fn.name !== "string" || !fn.name.trim()) continue;
    const { args, error } = parseToolArgsSafely(typeof fn.arguments === "string" ? fn.arguments : "{}");
    return [{
      id: typeof tc.id === "string" && tc.id.trim() ? tc.id : crypto.randomUUID(),
      name: fn.name,
      args,
      parseError: error,
    }];
  }

  const text = extractAssistantText(responseMessage);
  if (!text) return [];

  const toolCalls: ExtractedToolCall[] = [];
  const runRe = /run\s*\(\s*(?:command\s*=\s*)?["']([^"']+)["']\s*\)/g;
  let m: RegExpExecArray | null;
  while ((m = runRe.exec(text)) !== null) {
    toolCalls.push({
      id: crypto.randomUUID(),
      name: "run",
      args: { command: cleanCommand(m[1]) },
      parseError: null,
    });
  }
  if (toolCalls.length > 0) return toolCalls;

  const lines = text.split("\n");
  for (const line of lines) {
    const stripped = line.replace(/^\s*\d+[.):-]\s*/, "").trim();
    if (stripped && COMMAND_VERBS.test(stripped)) {
      toolCalls.push({
        id: crypto.randomUUID(),
        name: "run",
        args: { command: cleanCommand(stripped) },
        parseError: null,
      });
    }
  }
  if (toolCalls.length > 0) return toolCalls;

  const patterns = [
    /Tool call run:\s*\n?\{?\s*"?command"?\s*[:=]\s*"([^"]+)"/,
    /<parameter\s+name="command">([^<]+)<\/parameter>/,
    /\[TOOL_CALL\][\s\S]*?--command\s+"([^"]+)"[\s\S]*?\[\/TOOL_CALL\]/,
    /command["\s:=]+["']([^"']+)["']/i,
  ];
  for (const re of patterns) {
    const match = text.match(re);
    if (match) {
      return [{
        id: crypto.randomUUID(),
        name: "run",
        args: { command: cleanCommand(match[1]) },
        parseError: null,
      }];
    }
  }

  return [];
}

function asTrimmedString(value: unknown): string | null {
  return typeof value === "string" && value.trim() ? value.trim() : null;
}

function asPositiveNumber(value: unknown): number | null {
  return typeof value === "number" && Number.isFinite(value) && value > 0 ? value : null;
}

function asStringArray(value: unknown): string[] {
  return Array.isArray(value)
    ? value.filter((item): item is string => typeof item === "string" && item.trim().length > 0)
      .map((item) => item.trim())
    : [];
}

function isToolError(result: string): boolean {
  return result.includes("not found")
    || result.includes("does not exist")
    || result.includes("requires")
    || result.includes("must be")
    || result.includes("Failed")
    || result.includes("Unknown command")
    || result.includes("Unknown tool")
    || result.includes("error");
}

async function executeCreateTask(
  args: Record<string, unknown>,
  timelineState: Awaited<ReturnType<typeof loadTimelineState>>,
  selectedClips: SelectedClipPayload[] | undefined,
  supabaseAdmin: SupabaseAdmin,
): Promise<{ result: string }> {
  const taskType = asTrimmedString(args.task_type);
  const prompt = asTrimmedString(args.prompt);
  if (!taskType || !prompt) {
    return { result: "create_task requires task_type and prompt." };
  }

  const referenceImageUrls = asStringArray(args.reference_image_urls);
  if (taskType === "image-to-video" && referenceImageUrls.length < 2) {
    return { result: "create_task image-to-video requires at least two reference_image_urls." };
  }
  if (taskType !== "text-to-image" && taskType !== "image-to-video" && referenceImageUrls.length === 0) {
    return { result: `create_task ${taskType} requires reference_image_urls.` };
  }

  const selectedReferenceClips = selectedClips?.filter((clip) => referenceImageUrls.includes(clip.url)) ?? [];
  const generationIds = resolveClipGenerationIds(selectedReferenceClips, timelineState.registry, timelineState.config);
  let shotId = generationIds.length ? await findShotForGenerations(supabaseAdmin, generationIds) : null;
  let shotNote = "";
  const shotName = asTrimmedString(args.shot_name);
  if (!shotId && shotName && generationIds.length > 0) {
    shotId = await createShotWithGenerations(supabaseAdmin, {
      projectId: timelineState.projectId,
      shotName,
      generationIds,
      // Append without another query; the RPC only shifts rows at or beyond this position.
      position: APPEND_SHOT_POSITION,
    });
    shotNote = ` Created shot ${shotName} (${shotId}).`;
  } else if (shotId) {
    shotNote = ` Reused shot ${shotId}.`;
  }

  const result = await createGenerationTask({
    project_id: timelineState.projectId,
    prompt,
    count: asPositiveNumber(args.count) ?? 1,
    task_type: taskType,
    reference_mode: TASK_TYPE_TO_REFERENCE_MODE[taskType],
    reference_image_url: referenceImageUrls[0],
    image_urls: taskType === "image-to-video" ? referenceImageUrls : undefined,
    shot_id: shotId ?? undefined,
  });
  return { result: `${result.result}${shotNote}`.trim() };
}

export async function runAgentLoop(
  options: RunAgentLoopOptions,
): Promise<RunAgentLoopResult> {
  const { session, userMessage, selectedClips, supabaseAdmin, logger } = options;

  const lastTurn = session.turns[session.turns.length - 1];
  const isDuplicate = userMessage && lastTurn?.role === "user" && lastTurn.content === userMessage;
  const turns = [...session.turns];
  if (userMessage && !isDuplicate) {
    const userTurn = createTurn("user", userMessage);
    if (selectedClips?.length) {
      userTurn.attachments = selectedClips.map((clip) => ({
        clipId: clip.clip_id,
        url: clip.url,
        mediaType: clip.media_type,
      }));
    }
    turns.push(userTurn);
  }
  let status: AgentSessionStatus = "processing";
  const summary = session.summary;

  try {
    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    const timelineState = await loadTimelineState(supabaseAdmin, session.timeline_id);
    const timelineSummary = viewTimeline(timelineState.config, timelineState.registry).result;
    const systemPrompt = buildTimelineAgentSystemPrompt({
      projectId: timelineState.projectId,
      timelineSummary,
      selectedClips,
    });
    const messages = buildInitialMessages(systemPrompt, turns);
    const startedAt = Date.now();

    // Triage the user message to pick provider: easy/okay → Kimi K2.5, hard → Claude
    const difficulty = userMessage
      ? await triageDifficulty(userMessage, logger)
      : "okay";

    for (let iteration = 0; iteration < LOOP_LIMIT; iteration += 1) {
      if (Date.now() - startedAt >= SOFT_TIMEOUT_MS) {
        status = "continue";
        break;
      }

      const currentStatus = await loadSessionStatus(supabaseAdmin, session.id);
      if (currentStatus === "cancelled") {
        status = "cancelled";
        break;
      }

      let completion;
      try {
        completion = await invokeLlm(
          {
            messages: messages as unknown[],
            tools: TIMELINE_AGENT_TOOLS as unknown[],
            tool_choice: "auto",
            temperature: 0.2,
            max_tokens: 4096,
            top_p: 1,
          },
          difficulty,
          logger,
        );
      } catch (llmError: unknown) {
        const text = `AI service error: ${toErrorMessage(llmError)}`;
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      const responseMessage = completion.choices[0]?.message;
      if (!responseMessage) {
        turns.push(createTurn("assistant", "No response from AI."));
        status = "waiting_user";
        break;
      }

      const extractedToolCalls = extractToolCalls(responseMessage);
      const assistantText = extractAssistantText(responseMessage);

      if (extractedToolCalls.length === 0) {
        const text = assistantText || "What would you like me to do?";
        turns.push(createTurn("assistant", text));
        messages.push({ role: "assistant", content: text });
        status = "waiting_user";
        break;
      }

      let hasError = false;
      for (const toolCall of extractedToolCalls) {
        const toolArgs = toolCall.args;
        const toolContent = toolCall.name === "run"
          ? (typeof toolArgs.command === "string" ? toolArgs.command : JSON.stringify(toolArgs))
          : JSON.stringify(toolArgs);
        turns.push(createToolTurn("tool_call", toolCall.name, toolContent, toolArgs));

        messages.push({
          role: "assistant",
          content: null,
          tool_calls: [{
            id: toolCall.id,
            type: "function" as const,
            function: { name: toolCall.name, arguments: JSON.stringify(toolArgs) },
          }],
        });

        const result = toolCall.parseError
          ? { result: toolCall.parseError }
          : toolCall.name === "run"
          ? await executeCommand(
            typeof toolArgs.command === "string" ? toolArgs.command : "",
            timelineState,
            session.timeline_id,
            supabaseAdmin,
          )
          : toolCall.name === "create_task"
          ? await executeCreateTask(toolArgs, timelineState, selectedClips, supabaseAdmin)
          : { result: `Unknown tool: ${toolCall.name}.` };

        turns.push(createToolTurn("tool_result", toolCall.name, result.result, toolArgs));
        messages.push({
          role: "tool",
          tool_call_id: toolCall.id,
          content: result.result,
        });

        if (isToolError(result.result)) {
          hasError = true;
          break;
        }
      }

      // Strip tool-call formatting junk from any assistant text
      if (assistantText) {
        const cleaned = assistantText
          .replace(/\[TOOL_CALL\][\s\S]*?\[\/TOOL_CALL\]/g, "")
          .replace(/<invoke[\s\S]*?<\/invoke>/g, "")
          .replace(/Tool call \w+:[\s\S]*?(?=\n\n|$)/g, "")
          .replace(/(?:run|create_task)\s*\([^)]*\)/g, "")
          .replace(/^\s*\d+[.):-]\s*(set-text|move|trim|delete|duplicate|add-text|set|view|find-issues|generate)\b.*$/gm, "")
          .trim();
        if (cleaned && cleaned.length > 2) {
          turns.push(createTurn("assistant", cleaned));
        }
      }

      // If a command failed, give the model structured recovery options
      if (hasError) {
        const lastResult = turns[turns.length - 1];
        messages.push({
          role: "user",

          role: "user",
          content: `Tool failed: "${lastResult?.content ?? "unknown error"}". You can: (1) run(command="...") with a corrected timeline command, (2) create_task({...}) with corrected task arguments, (3) run(command="view") to inspect the timeline, or (4) reply in plain text to tell the user what went wrong.`,
        });
        continue;
      }
    }

    if (status === "processing") {
      status = "continue";
    }

    await persistSessionState(supabaseAdmin, {
      sessionId: session.id,
      status,
      turns,
      summary,
    });

    logger.info("Agent loop completed", {
      session_id: session.id,
      status,
      turns_added: turns.length - session.turns.length,
    });

    return { status, turns, summary };
  } catch (error: unknown) {
    const errorDetail = toErrorMessage(error);
    console.error(`[agent] FATAL: ${errorDetail}`);
    logger.error("Agent loop failed", {
      session_id: session.id,
      error: errorDetail,
    });

    turns.push(createTurn("assistant", `[INTERNAL ERROR] ${errorDetail}`));

    try {
      await persistSessionState(supabaseAdmin, {
        sessionId: session.id,
        status: "error",
        turns,
        summary,
      });
    } catch (persistError: unknown) {
      logger.error("Failed to persist error state", {
        session_id: session.id,
        error: toErrorMessage(persistError),
      });
    }

    return { status: "error", turns, summary };
  }
}

